/**
 * ZAP DESIGN ENGINE - METRO BLAST SCRIPT
 * Operation: SWARM EXTRACTION
 * 
 * Target: /Users/zap/Workspace/references/metronic/metronic-tailwind-react-demos/typescript/nextjs/components/ui/
 * Destination: /Users/zap/Workspace/olympus/packages/zap-design/src/components/ui/
 * 
 * Directives for Agent Spike:
 * 1. Read Metro component natively.
 * 2. Strip all proprietary CSS.
 * 3. Verify M3 token inheritance (m3_mapping.css handles translation).
 * 4. Write pure React DOM to Olympus zap-design.
 */

import { execSync } from 'child_process';
import * as fs from 'fs';
import * as path from 'path';

const SOURCE_DIR = '/Users/zap/Workspace/references/metronic/metronic-tailwind-react-demos/typescript/nextjs/components/ui';
const DEST_DIR = '/Users/zap/Workspace/olympus/packages/zap-design/src/components/ui';

// Phase 1 Blast already extracted: card, button, badge, input, table, dialog.
// Phase 2 Queue
const blastQueue = [
    'accordion-menu.tsx',
    'accordion.tsx',
    'alert-dialog.tsx',
    'alert.tsx',
    'avatar-group.tsx',
    'avatar.tsx',
    'breadcrumb.tsx',
    'calendar.tsx',
    'carousel.tsx',
    'chart.tsx',
    'checkbox.tsx',
    'collapsible.tsx',
    'command.tsx',
    'context-menu.tsx',
    'data-grid.tsx',
    'datefield.tsx',
    'drawer.tsx',
    'dropdown-menu.tsx',
    'form.tsx',
    'grid-background.tsx',
    'kanban.tsx',
    'navigation-menu.tsx',
    'pagination.tsx',
    'popover.tsx',
    'progress.tsx',
    'radio-group.tsx',
    'scroll-area.tsx',
    'select.tsx',
    'separator.tsx',
    'sheet.tsx',
    'skeleton.tsx',
    'slider.tsx',
    'switch.tsx',
    'tabs.tsx',
    'textarea.tsx',
    'tooltip.tsx',
];

console.log(`[ZAP BLAST] Initializing Omni Router queue for Agent Spike.`);
console.log(`[ZAP BLAST] Target payload: ${blastQueue.length} components.`);

function createJobPayload(componentName: string) {
    return {
        agent: 'Spike',
        protocol: 'zap-spike-extraction-protocol',
        source: path.join(SOURCE_DIR, componentName),
        destination: path.join(DEST_DIR, componentName),
        strictCssExclusion: true,
    };
}

async function runBlast() {
    if (!fs.existsSync(DEST_DIR)) {
        fs.mkdirSync(DEST_DIR, { recursive: true });
    }

    for (const component of blastQueue) {
        const payload = createJobPayload(component);

        // Simulating Omni Router dispatch
        console.log(`[Omni Router] Dispatching Job to Spike: Extracting ${component}...`);

        try {
            // Here we would push strictly to the Redis Queue/Omni Router for Spike to compute asynchronously.
            // For local simulation / fallback execution:
            // execSync(`npx ts-node path/to/spike-agent-trigger.ts '${JSON.stringify(payload)}'`);
            console.log(`  -> Job queued successfully [Status: PENDING].`);
        } catch (e) {
            console.error(`  -> Failed to queue ${component}:`, e);
        }
    }

    console.log(`[ZAP BLAST] Queue complete. Monitoring Jerry for TestSprite validation rings.`);
}

runBlast();

'use client';

import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

interface BomItem {
  id: string;
  name: string;
}

interface BomLine {
  id: string;
  component: BomItem;
  quantity_needed: string;
  unit_of_measure: string;
}

interface TargetEntity {
  id: string;
  name: string;
  type: 'VARIANT' | 'SEMI_PRODUCT';
  boms: BomLine[];
}

export function BomBuilderModal({ tenantId }: { tenantId: string }) {
  const [targets, setTargets] = useState<TargetEntity[]>([]);
  const [ingredients, setIngredients] = useState<BomItem[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<TargetEntity | null>(null);
  const [loading, setLoading] = useState(true);

  // New BOM Entry State
  const [newLine, setNewLine] = useState({
    component_item_id: '',
    quantity_needed: '1',
    unit_of_measure: 'oz'
  });

  useEffect(() => {
    fetchData();
  }, [tenantId]);

  const fetchData = async () => {
    try {
      setLoading(true);
      // Fetch targets (Variants + Semis)
      const resBom = await fetch(`/api/inventory/bom?tenant_id=${tenantId}`);
      // Fetch potential ingredients
      const resItems = await fetch(`/api/inventory/items?tenant_id=${tenantId}`);

      if (resBom.ok && resItems.ok) {
        const { variants, semiProducts } = await resBom.json();
        const items = await resItems.json();

        // Normalize targets for the UI dropdown
        const normalizedTargets = [
          ...variants.map((v: any) => ({
            id: v.id,
            name: `${v.product.name} - ${v.name || 'Default'}`,
            type: 'VARIANT',
            boms: v.bom_recipes_bom_recipes_product_variant_idToproduct_variants.map((b: any) => ({
              id: b.id,
              component: b.raw_ingredients_bom_recipes_component_item_idToraw_ingredients,
              quantity_needed: String(b.quantity_needed),
              unit_of_measure: b.unit_of_measure
            }))
          })),
          ...semiProducts.map((sp: any) => ({
            id: sp.id,
            name: `(WIP) ${sp.name}`,
            type: 'SEMI_PRODUCT',
            boms: sp.bom_recipes_bom_recipes_output_item_idToraw_ingredients.map((b: any) => ({
              id: b.id,
              component: b.raw_ingredients_bom_recipes_component_item_idToraw_ingredients,
              quantity_needed: String(b.quantity_needed),
              unit_of_measure: b.unit_of_measure
            }))
          }))
        ];

        setTargets(normalizedTargets);
        setIngredients(items);

        // Maintain selection if it exists
        if (selectedTarget) {
            const updated = normalizedTargets.find(t => t.id === selectedTarget.id);
            if (updated) setSelectedTarget(updated);
        }
      }
    } catch (error) {
      console.error('Failed to fetch BOM data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAddLine = async () => {
    if (!selectedTarget || !newLine.component_item_id) return;

    try {
      const payload = {
        tenant_id: tenantId,
        product_variant_id: selectedTarget.type === 'VARIANT' ? selectedTarget.id : null,
        output_item_id: selectedTarget.type === 'SEMI_PRODUCT' ? selectedTarget.id : null,
        component_item_id: newLine.component_item_id,
        quantity_needed: newLine.quantity_needed,
        unit_of_measure: newLine.unit_of_measure
      };

      const res = await fetch('/api/inventory/bom', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        // Reset form and refresh
        setNewLine({ component_item_id: '', quantity_needed: '1', unit_of_measure: 'oz' });
        fetchData();
      }
    } catch (error) {
      console.error('Failed to add BOM line:', error);
    }
  };

  if (loading) return <div className="p-12 text-center text-gray-500">Loading Configuration...</div>;

  return (
    <div className="bg-white p-6 rounded-xl border border-gray-200">

      <div className="flex gap-8">
        {/* Left Column: Target Selector */}
        <div className="w-1/3 border-r pr-6">
          <h3 className="text-lg font-bold mb-4">Select Output Entity</h3>
          <p className="text-sm text-gray-500 mb-4">Choose a POS Variant or a Semi-Product to define its required ingredients.</p>

          <div className="space-y-2 max-h-[400px] overflow-y-auto">
            {targets.map(target => (
              <button
                key={target.id}
                onClick={() => setSelectedTarget(target)}
                className={`w-full text-left px-4 py-3 rounded-lg border transition-colors ${selectedTarget?.id === target.id ? 'bg-black text-white border-black' : 'bg-white hover:bg-gray-50 border-gray-200'}`}
              >
                <div className="font-medium text-sm">{target.name}</div>
                <div className={`text-xs mt-1 ${selectedTarget?.id === target.id ? 'text-gray-300' : 'text-gray-500'}`}>
                  Type: {target.type} | {target.boms.length} entries
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Right Column: BOM Configurator */}
        <div className="w-2/3 pl-2">
          {!selectedTarget ? (
             <div className="h-full flex flex-col items-center justify-center text-gray-400">
               <p>Select an output entity on the left to view and edit its Recipe (BOM).</p>
             </div>
          ) : (
            <div>
               <div className="mb-6 pb-4 border-b">
                 <h3 className="text-xl font-bold">{selectedTarget.name}</h3>
                 <span className="text-sm text-gray-500">Routing Type: {selectedTarget.type}</span>
               </div>

               {/* Existing BOM Lines */}
               <div className="mb-8">
                 <h4 className="text-sm font-bold uppercase tracking-wider text-gray-500 mb-3">Current Recipe Lines</h4>
                 {selectedTarget.boms.length === 0 ? (
                   <div className="bg-gray-50 p-4 rounded-lg text-sm text-center text-gray-500">No ingredients mapped yet.</div>
                 ) : (
                   <ul className="space-y-2">
                     {selectedTarget.boms.map(bom => (
                       <li key={bom.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border">
                         <span className="font-medium">{bom.component.name}</span>
                         <span className="text-sm bg-white px-3 py-1 rounded border">
                           {Number(bom.quantity_needed).toFixed(2)} {bom.unit_of_measure}
                         </span>
                       </li>
                     ))}
                   </ul>
                 )}
               </div>

               {/* Add New Line Form */}
               <div className="bg-gray-50 p-6 rounded-xl border border-dashed border-gray-300">
                 <h4 className="text-sm font-bold mb-4">Add Ingredient Route</h4>
                 <div className="flex gap-4 items-end">
                   <div className="flex-2 w-1/2">
                     <label className="text-xs font-semibold uppercase text-gray-600 mb-1 block">Component / Raw Material</label>
                     <select 
                       className="w-full flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                       value={newLine.component_item_id}
                       onChange={(e) => setNewLine({...newLine, component_item_id: e.target.value})}
                     >
                       <option value="" disabled>Select an ingredient...</option>
                       {ingredients.map(ing => (
                         <option key={ing.id} value={ing.id}>{ing.name}</option>
                       ))}
                     </select>
                   </div>
                   <div className="flex-1">
                     <label className="text-xs font-semibold uppercase text-gray-600 mb-1 block">Qty Needed</label>
                     <Input 
                       type="number" 
                       step="0.01" 
                       value={newLine.quantity_needed}
                       onChange={(e) => setNewLine({...newLine, quantity_needed: e.target.value})} 
                     />
                   </div>
                   <div className="flex-1">
                     <label className="text-xs font-semibold uppercase text-gray-600 mb-1 block">UoM</label>
                     <Input 
                       value={newLine.unit_of_measure}
                       onChange={(e) => setNewLine({...newLine, unit_of_measure: e.target.value})} 
                     />
                   </div>
                   <Button onClick={handleAddLine} disabled={!newLine.component_item_id} variant="secondary">Add</Button>
                 </div>
               </div>

            </div>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

interface InventoryItem {
  id: string;
  name: string;
  item_type: string;
  base_unit_measure: string;
  current_cost: string;
  yield_percentage: string;
}

export function ItemMasterDataGrid({ tenantId }: { tenantId: string }) {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);

  // New Item Form State
  const [newItemParams, setNewItemParams] = useState({
    name: '',
    base_unit_measure: 'oz',
    current_cost: '0.00',
    yield_percentage: '100.00'
  });

  useEffect(() => {
    fetchItems();
  }, [tenantId]);

  const fetchItems = async () => {
    try {
      setLoading(true);
      const res = await fetch(`/api/inventory/items?tenant_id=${tenantId}`);
      if (res.ok) {
        const data = await res.json();
        setItems(data);
      }
    } catch (error) {
      console.error('Failed to fetch items:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async () => {
    try {
      const res = await fetch('/api/inventory/items', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          tenant_id: tenantId,
          ...newItemParams,
          current_cost: parseFloat(newItemParams.current_cost),
          yield_percentage: parseFloat(newItemParams.yield_percentage)
        }),
      });

      if (res.ok) {
        setShowModal(false);
        fetchItems(); // Refresh the grid
      }
    } catch (error) {
      console.error('Failed to create item:', error);
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl border border-gray-200">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-semibold">Physical Items Master List</h2>
        <Button onClick={() => setShowModal(true)}>Add New Physical Item</Button>
      </div>

      {loading ? (
        <div className="text-center py-6 text-gray-500">Loading items...</div>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left text-gray-500">
            <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b">
              <tr>
                <th scope="col" className="px-6 py-3">Item Name</th>
                <th scope="col" className="px-6 py-3">Type</th>
                <th scope="col" className="px-6 py-3">Base Unit</th>
                <th scope="col" className="px-6 py-3">Current Cost</th>
                <th scope="col" className="px-6 py-3">Yield %</th>
                <th scope="col" className="px-6 py-3 text-right">Action</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item.id} className="bg-white border-b hover:bg-gray-50">
                  <td className="px-6 py-4 font-medium text-gray-900">{item.name}</td>
                  <td className="px-6 py-4">
                    <span className="bg-blue-100 text-blue-800 text-xs font-semibold mr-2 px-2.5 py-0.5 rounded">
                      {item.item_type || 'RAW_MATERIAL'}
                    </span>
                  </td>
                  <td className="px-6 py-4">{item.base_unit_measure}</td>
                  <td className="px-6 py-4">${Number(item.current_cost).toFixed(2)}</td>
                  <td className="px-6 py-4">{Number(item.yield_percentage).toFixed(2)}%</td>
                  <td className="px-6 py-4 text-right">
                    <Button variant="ghost" size="sm">Edit</Button>
                  </td>
                </tr>
              ))}
              {items.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                    No physical items found in the master list.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* Simple Creation Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
          <div className="bg-white rounded-xl p-8 w-full max-w-md">
            <h3 className="text-lg font-bold mb-4">Create New Physical Item</h3>
            <div className="space-y-4">
              <div>
                 <label className="text-sm font-medium">Item Name</label>
                 <Input 
                   value={newItemParams.name} 
                   onChange={(e) => setNewItemParams({...newItemParams, name: e.target.value})} 
                   placeholder="e.g. Tomato Paste" 
                 />
              </div>
              <div>
                 <label className="text-sm font-medium">Base Unit of Measure</label>
                 <Input 
                   value={newItemParams.base_unit_measure} 
                   onChange={(e) => setNewItemParams({...newItemParams, base_unit_measure: e.target.value})} 
                   placeholder="e.g. oz, lb, can" 
                 />
              </div>
              <div className="flex gap-4">
                <div className="flex-1">
                  <label className="text-sm font-medium">Current Cost ($)</label>
                  <Input 
                    type="number"
                    step="0.01"
                    value={newItemParams.current_cost} 
                    onChange={(e) => setNewItemParams({...newItemParams, current_cost: e.target.value})} 
                  />
                </div>
                <div className="flex-1">
                  <label className="text-sm font-medium">Yield Percentage</label>
                  <Input 
                    type="number"
                    step="0.01"
                    value={newItemParams.yield_percentage} 
                    onChange={(e) => setNewItemParams({...newItemParams, yield_percentage: e.target.value})} 
                  />
                </div>
              </div>
            </div>
            <div className="mt-6 flex justify-end gap-3">
              <Button variant="outline" onClick={() => setShowModal(false)}>Cancel</Button>
              <Button onClick={handleCreate}>Save Item</Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

