import { NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function PATCH(request: Request) {
    try {
        const body = await request.json();
        const { filePath, isLocked } = body;

        if (!filePath || typeof isLocked !== 'boolean') {
            return NextResponse.json({ error: "Missing required fields: filePath and isLocked (boolean)" }, { status: 400 });
        }

        const ticket = await prisma.assetTicket.update({
            where: { filePath },
            data: { isLocked }
        });

        return NextResponse.json({ data: ticket });
    } catch (error: any) {
        console.error("Failed to update asset lock status:", error);
        return NextResponse.json({ error: error.message || "Failed to update asset lock status" }, { status: 500 });
    } finally {
        await prisma.$disconnect();
    }
}

import { NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const page = parseInt(searchParams.get('page') || '1', 10);
        const limitParam = searchParams.get('limit');
        const isAll = limitParam === '0';
        const limit = limitParam ? parseInt(limitParam, 10) : 20;
        const status = searchParams.get('status');
        const search = searchParams.get('search');

        const skip = isAll ? 0 : (page - 1) * limit;

        const whereCondition: any = {};
        if (status) {
            whereCondition.status = status;
        }

        if (search) {
            if (search.startsWith('#')) {
                const tagTerm = search.substring(1);
                whereCondition.tags = { contains: tagTerm };
            } else {
                whereCondition.OR = [
                    { filePath: { contains: search } },
                    { trackingId: { contains: search } },
                    { originalName: { contains: search } },
                    { filePathB: { contains: search } },
                    { filePathZap: { contains: search } },
                    { category: { contains: search } },
                    { tags: { contains: search } },
                ];
            }
        }

        const [tickets, total] = await Promise.all([
            prisma.assetTicket.findMany({
                where: whereCondition,
                skip,
                take: isAll ? undefined : limit,
                orderBy: { updatedAt: 'desc' }
            }),
            prisma.assetTicket.count({ where: whereCondition })
        ]);

        return NextResponse.json({
            data: tickets,
            meta: {
                total,
                page,
                limit,
                totalPages: Math.ceil(total / limit)
            }
        });
    } catch (error: any) {
        console.error("Failed to fetch asset tickets:", error);
        return NextResponse.json({ error: error.message || "Failed to fetch asset tickets" }, { status: 500 });
    } finally {
        await prisma.$disconnect();
    }
}

import { NextResponse } from 'next/server';
import fs from 'fs';
import path from 'path';

export const dynamic = 'force-dynamic';

export async function GET(request: Request) {
    const { searchParams } = new URL(request.url);
    const type = searchParams.get('type'); // "original" or "generated"
    let filePath = searchParams.get('path'); // e.g. "/media/avatars/300-1.jpg"

    if (!filePath) {
        return new NextResponse("Missing path parameter", { status: 400 });
    }

    // Ensure the path starts with /media
    if (!filePath.startsWith('/media')) {
        filePath = '/media' + (filePath.startsWith('/') ? filePath.substring(1) : filePath);
    }

    let fullPath = "";
    if (type === "original") {
        fullPath = path.join("/Users/zap/Workspace/metronic-v9.4.5/metronic-tailwind-react-demos/typescript/nextjs/public", filePath);
    } else {
        // Look in the actual ZAP Design public folder
        fullPath = path.join(process.cwd(), "public", filePath);
    }

    if (!fs.existsSync(fullPath)) {
        // Return a transparent 1x1 pixel instead of 404 to avoid broken image icons ruining the UI
        const transparentPixel = Buffer.from("iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=", "base64");
        return new NextResponse(transparentPixel, {
            headers: { 'Content-Type': 'image/png' }
        });
    }

    try {
        const fileBuffer = fs.readFileSync(fullPath);

        let mime = 'image/jpeg'; // Default fallback
        if (fileBuffer.length > 4) {
            const header = fileBuffer.toString('hex', 0, 4).toUpperCase();
            if (header === '89504E47') {
                mime = 'image/png';
            } else if (header.startsWith('FFD8FF')) {
                mime = 'image/jpeg';
            } else if (header === '47494638') {
                mime = 'image/gif';
            } else if (fileBuffer.toString('utf8', 0, 100).includes('<svg') || fileBuffer.toString('utf8', 0, 100).includes('<?xml')) {
                mime = 'image/svg+xml';
            } else {
                // Fallback to extension if magic bytes fail
                const ext = path.extname(fullPath).toLowerCase();
                if (ext === '.svg') mime = 'image/svg+xml';
                if (ext === '.png') mime = 'image/png';
                if (ext === '.webp') mime = 'image/webp';
                if (ext === '.gif') mime = 'image/gif';
            }
        }

        return new NextResponse(fileBuffer, { headers: { 'Content-Type': mime } });
    } catch (e) {
        return new NextResponse("Error reading file", { status: 500 });
    }
}

