'use client';

import React, { useState, useCallback, useRef } from 'react';
import dynamic from 'next/dynamic';
import { Wrapper } from '@/components/dev/Wrapper';
import { Heading } from '@/genesis/atoms/typography/headings';
import { Icon } from '@/genesis/atoms/icons/Icon';
import { Button } from '@/genesis/atoms/interactive/buttons';
import { useTheme } from '@/components/ThemeContext';

// Excalidraw must be loaded client-side only (canvas/DOM APIs)
const Excalidraw = dynamic(
    async () => {
        const mod = await import('@excalidraw/excalidraw');
        return mod.Excalidraw;
    },
    { ssr: false, loading: () => <DiagramSkeleton /> }
);

// Dynamic import for exportToBlob (used for PNG snapshots)
const getExportToBlob = async () => {
    const mod = await import('@excalidraw/excalidraw');
    return mod.exportToBlob;
};

// Import types separately (these are safe for SSR — they're just type declarations)
type ExcalidrawElement = import('@excalidraw/excalidraw/element/types').ExcalidrawElement;
type BinaryFiles = import('@excalidraw/excalidraw/types').BinaryFiles;
type ExcalidrawImperativeAPI = import('@excalidraw/excalidraw/types').ExcalidrawImperativeAPI;

// ─── SKELETON ───────────────────────────────────────────────────────────────────

const DiagramSkeleton = () => (
    <div className="w-full h-full flex items-center justify-center bg-surface-container-lowest">
        <div className="flex flex-col items-center gap-4 animate-pulse">
            <Icon name="draw" size={48} className="text-muted-foreground/30" />
            <p className="text-sm font-bold text-muted-foreground/50 uppercase tracking-widest">Loading canvas...</p>
        </div>
    </div>
);

// ─── FILE LOADER ────────────────────────────────────────────────────────────────

interface ExcalidrawScene {
    type?: string;
    version?: number;
    source?: string;
    elements?: readonly ExcalidrawElement[];
    appState?: Record<string, unknown>;
    files?: BinaryFiles;
}

const loadExcalidrawFile = (file: File): Promise<ExcalidrawScene> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target?.result as string);
                resolve(json);
            } catch {
                reject(new Error('Invalid .excalidraw JSON file'));
            }
        };
        reader.onerror = () => reject(new Error('Failed to read file'));
        reader.readAsText(file);
    });
};

// ─── TOOLBAR ────────────────────────────────────────────────────────────────────

const DiagramToolbar = ({
    onLoadFile,
    onImportImage,
    onSave,
    onExport,
    onClear,
    fileName,
    saveStatus,
}: {
    onLoadFile: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onImportImage: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onSave: () => void;
    onExport: () => void;
    onClear: () => void;
    fileName: string | null;
    saveStatus: 'idle' | 'saving' | 'saved' | 'error';
}) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const imageInputRef = useRef<HTMLInputElement>(null);

    return (
        <div className="h-14 flex items-center justify-between px-6 bg-surface border-b border-border/50 shrink-0">
            <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                    <Icon name="draw" size={20} className="text-primary" />
                    <Heading level={5} className="text-foreground">
                        Diagrams
                    </Heading>
                </div>
                <span className="text-[9px] font-black bg-primary text-on-primary px-2 py-0.5 uppercase tracking-widest rounded-sm">
                    EXCALIDRAW
                </span>
                {fileName && (
                    <span className="text-[10px] font-dev text-transform-tertiary text-muted-foreground bg-on-surface/5 px-2 py-1 rounded-md">
                        {fileName}
                    </span>
                )}
            </div>

            <div className="flex items-center gap-2">
                {/* Load .excalidraw file */}
                <input
                    ref={fileInputRef}
                    type="file"
                    accept=".excalidraw,.json"
                    onChange={onLoadFile}
                    className="hidden"
                    aria-label="Load Excalidraw file"
                />
                <Button
                    visualStyle="ghost" variant="flat"
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-bold uppercase tracking-wider rounded-lg bg-on-surface/5 hover:bg-primary hover:text-on-primary text-foreground transition-all"
                    title="Open .excalidraw file"
                >
                    <Icon name="folder_open" size={16} />
                    Open
                </Button>

                {/* Import Image */}
                <input
                    ref={imageInputRef}
                    type="file"
                    accept=".png,.jpg,.jpeg,.gif,.svg,.webp"
                    onChange={onImportImage}
                    className="hidden"
                    aria-label="Import image to canvas"
                />
                <Button
                    visualStyle="ghost" variant="flat"
                    onClick={() => imageInputRef.current?.click()}
                    className="flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-bold uppercase tracking-wider rounded-lg bg-on-surface/5 hover:bg-primary hover:text-on-primary text-foreground transition-all"
                    title="Import image onto canvas"
                >
                    <Icon name="image" size={16} />
                    Image
                </Button>

                {/* Save to project */}
                <Button
                    visualStyle="ghost" variant="flat"
                    onClick={onSave}
                    disabled={saveStatus === 'saving'}
                    className="flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-bold uppercase tracking-wider rounded-lg bg-primary/10 hover:bg-primary hover:text-on-primary text-primary border border-primary/20 transition-all disabled:opacity-50"
                    title="Save to project (AI can read this)"
                >
                    <Icon name={saveStatus === 'saved' ? 'check_circle' : 'save'} size={16} />
                    {saveStatus === 'saving' ? 'Saving...' : saveStatus === 'saved' ? 'Saved' : 'Save'}
                </Button>

                {/* Separator */}
                <div className="w-px h-6 bg-border/50" />

                {/* Export download */}
                <Button
                    visualStyle="ghost" variant="flat"
                    onClick={onExport}
                    className="flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-bold uppercase tracking-wider rounded-lg bg-on-surface/5 hover:bg-primary hover:text-on-primary text-foreground transition-all"
                    title="Download as .excalidraw JSON"
                >
                    <Icon name="download" size={16} />
                    Export
                </Button>

                {/* Clear */}
                <Button
                    visualStyle="ghost" variant="flat"
                    onClick={onClear}
                    className="flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-bold uppercase tracking-wider rounded-lg bg-on-surface/5 hover:bg-state-error hover:text-on-primary text-muted-foreground transition-all"
                    title="Clear canvas"
                >
                    <Icon name="delete" size={16} />
                </Button>
            </div>
        </div>
    );
};

// ─── MAIN PAGE ──────────────────────────────────────────────────────────────────

export default function DiagramsPage() {
    const { theme } = useTheme();
    const [initialData, setInitialData] = useState<ExcalidrawScene | null>(null);
    const [fileName, setFileName] = useState<string | null>(null);
    const [excalidrawAPI, setExcalidrawAPI] = useState<ExcalidrawImperativeAPI | null>(null);
    const [key, setKey] = useState(0); // force re-mount on file load

    // Inject Excalidraw CSS — Turbopack can't resolve the package's conditional CSS export
    useEffect(() => {
        const id = 'excalidraw-css';
        if (!document.getElementById(id)) {
            const link = document.createElement('link');
            link.id = id;
            link.rel = 'stylesheet';
            link.href = '/vendor/excalidraw.css';
            document.head.appendChild(link);
        }
        // Inject ZAP theme override (must load AFTER Excalidraw CSS)
        const themeId = 'excalidraw-theme-css';
        if (!document.getElementById(themeId)) {
            const themeLink = document.createElement('link');
            themeLink.id = themeId;
            themeLink.rel = 'stylesheet';
            themeLink.href = '/vendor/excalidraw-theme.css';
            document.head.appendChild(themeLink);
        }
    }, []);

    const handleLoadFile = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        try {
            const scene = await loadExcalidrawFile(file);
            setFileName(file.name);
            setInitialData(scene);
            setKey(prev => prev + 1); // re-mount Excalidraw with new data
        } catch (err) {
            console.error('Failed to load .excalidraw file:', err);
        }

        // Reset input so same file can be re-loaded
        e.target.value = '';
    }, []);

    const handleImportImage = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !excalidrawAPI) return;

        try {
            // Read as data URL for Excalidraw's binary file storage
            const dataUrl = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => resolve(reader.result as string);
                reader.onerror = () => reject(new Error('Failed to read image'));
                reader.readAsDataURL(file);
            });

            // Get image dimensions
            const img = new Image();
            await new Promise<void>((resolve) => {
                img.onload = () => resolve();
                img.src = dataUrl;
            });

            // Generate unique file ID
            const fileId = `img_${Date.now()}_${Math.random().toString(36).slice(2, 8)}` as unknown as ExcalidrawElement['id'];

            // Register binary file with Excalidraw
            excalidrawAPI.addFiles([{
                id: fileId,
                dataURL: dataUrl,
                mimeType: file.type,
                created: Date.now(),
                lastRetrieved: Date.now(),
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            } as any]);

            // Scale image to fit nicely (max 800px wide)
            const maxWidth = 800;
            const scale = img.width > maxWidth ? maxWidth / img.width : 1;
            const width = img.width * scale;
            const height = img.height * scale;

            // Get current scroll position to place image in viewport center
            const appState = excalidrawAPI.getAppState();
            const centerX = (appState.scrollX * -1) + (appState.width / 2) - (width / 2);
            const centerY = (appState.scrollY * -1) + (appState.height / 2) - (height / 2);

            // Add image element to scene
            const existingElements = excalidrawAPI.getSceneElements();
            excalidrawAPI.updateScene({
                elements: [
                    ...existingElements,
                    {
                        type: 'image',
                        id: `el_${Date.now()}`,
                        x: centerX,
                        y: centerY,
                        width,
                        height,
                        fileId,
                        status: 'saved',
                        version: 1,
                        versionNonce: Math.floor(Math.random() * 1000000),
                        isDeleted: false,
                        fillStyle: 'solid',
                        strokeWidth: 1,
                        strokeStyle: 'solid',
                        roughness: 0,
                        opacity: 100,
                        groupIds: [],
                        strokeColor: 'transparent',
                        backgroundColor: 'transparent',
                        seed: Math.floor(Math.random() * 1000000),
                        angle: 0,
                        boundElements: null,
                        updated: Date.now(),
                        link: null,
                        locked: false,
                        scale: [1, 1] as [number, number],
                        crop: null,
                    } as unknown as ExcalidrawElement,
                ],
            });
        } catch (err) {
            console.error('Failed to import image:', err);
        }

        e.target.value = '';
    }, [excalidrawAPI]);

    const getSceneData = useCallback(() => {
        if (!excalidrawAPI) return null;
        const elements = excalidrawAPI.getSceneElements();
        const appState = excalidrawAPI.getAppState();
        const files = excalidrawAPI.getFiles();
        return {
            type: 'excalidraw',
            version: 2,
            source: 'zap-design-engine',
            elements,
            appState: {
                viewBackgroundColor: appState.viewBackgroundColor,
                gridSize: appState.gridSize,
            },
            files,
        };
    }, [excalidrawAPI]);

    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');

    const handleSave = useCallback(async () => {
        const scene = getSceneData();
        if (!scene || !excalidrawAPI) return;

        setSaveStatus('saving');
        try {
            // Generate PNG snapshot
            let snapshot: string | null = null;
            try {
                const exportToBlob = await getExportToBlob();
                const blob = await exportToBlob({
                    elements: excalidrawAPI.getSceneElements(),
                    appState: { ...excalidrawAPI.getAppState(), exportWithDarkMode: false },
                    files: excalidrawAPI.getFiles(),
                    maxWidthOrHeight: 1920,
                    getDimensions: () => ({ width: 1920, height: 1080, scale: 1 }),
                });
                snapshot = await new Promise<string>((resolve) => {
                    const reader = new FileReader();
                    reader.onloadend = () => resolve(reader.result as string);
                    reader.readAsDataURL(blob);
                });
            } catch (snapshotErr) {
                console.warn('PNG snapshot failed, saving scene only:', snapshotErr);
            }

            // Save scene + snapshot to disk
            const res = await fetch('/api/diagrams/save', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    scene,
                    snapshot,
                    fileName: fileName?.replace(/\.(excalidraw|json)$/, '') || 'canvas',
                }),
            });

            if (!res.ok) throw new Error('Save failed');

            // Also add to Excalidraw Library panel
            const elements = excalidrawAPI.getSceneElements();
            if (elements.length > 0) {
                const newLibraryItem = {
                    id: `lib_${Date.now()}`,
                    status: 'published',
                    elements: elements.map(el => ({ ...el })),
                    created: Date.now(),
                };

                // Get existing library from API, merge new item
                const libRes = await fetch('/api/diagrams/library');
                const libData = await libRes.json();
                const existingLib = libData.libraryItems || [];
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const updatedLibrary = [...existingLib, newLibraryItem] as any[];

                excalidrawAPI.updateLibrary({
                    libraryItems: updatedLibrary,
                    merge: false,
                    openLibraryMenu: true,
                });

                // Persist library to disk
                await fetch('/api/diagrams/library', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ libraryItems: updatedLibrary }),
                });
            }

            const result = await res.json();
            console.log('Diagram saved:', result);
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 3000);
        } catch (err) {
            console.error('Failed to save diagram:', err);
            setSaveStatus('error');
            setTimeout(() => setSaveStatus('idle'), 3000);
        }
    }, [getSceneData, excalidrawAPI, fileName]);

    const handleExport = useCallback(() => {
        const data = getSceneData();
        if (!data) return;

        const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = fileName || 'diagram.excalidraw';
        a.click();
        URL.revokeObjectURL(url);
    }, [getSceneData, fileName]);

    const handleClear = useCallback(() => {
        setInitialData(null);
        setFileName(null);
        setKey(prev => prev + 1);
    }, []);

    return (
        <Wrapper
            identity={{
                displayName: "DiagramsPage",
                filePath: "app/debug/metro/diagrams/page.tsx",
                type: "Page/Canvas",
                architecture: "TOOLS // EXCALIDRAW"
            }}
            className="!h-full !flex-1 !overflow-hidden"
        >
            <div className="flex flex-col w-full h-full overflow-hidden">
                <DiagramToolbar
                    onLoadFile={handleLoadFile}
                    onImportImage={handleImportImage}
                    onSave={handleSave}
                    onExport={handleExport}
                    onClear={handleClear}
                    fileName={fileName}
                    saveStatus={saveStatus}
                />

                {/* Excalidraw Canvas — fills remaining space */}
                <div className="flex-1 relative min-h-0">
                    <Excalidraw
                        key={key}
                        excalidrawAPI={(api: ExcalidrawImperativeAPI) => {
                            setExcalidrawAPI(api);
                            // Load persisted library on init
                            fetch('/api/diagrams/library')
                                .then(r => r.json())
                                .then(data => {
                                    if (data.libraryItems?.length > 0) {
                                        api.updateLibrary({
                                            libraryItems: data.libraryItems,
                                            merge: true,
                                            openLibraryMenu: false,
                                        });
                                    }
                                })
                                .catch(() => { /* library load is best-effort */ });
                        }}
                        initialData={initialData ? {
                            elements: initialData.elements,
                            appState: initialData.appState as Record<string, unknown>,
                            files: initialData.files,
                        } : undefined}
                        UIOptions={{
                            canvasActions: {
                                loadScene: true,
                                export: { saveFileToDisk: true },
                                saveToActiveFile: false,
                            },
                        }}
                        theme="light"
                    />
                </div>
            </div>
        </Wrapper>
    );
}

