/**
 * ATOM: METADATA
 * Foundational unit for categorical tags
 */
export const MetadataAtom: React.FC<{ tags: Array<{ label: string, type?: 'error' | 'warning' | 'info' | 'success' | 'design' | 'planning' }>; className?: string }> = ({ tags, className = '' }) => {

    const getTagStyles = (type?: string) => {
        switch (type) {
            case 'error': return 'bg-[#FF4A4A] text-white';
            case 'warning': return 'bg-[#FFAA00] text-black';
            case 'success': return 'bg-[#00E676] text-black';
            case 'design': return 'bg-[#00B0FF] text-white';
            case 'planning': return 'bg-[#DFFF00] text-black';
            case 'info':
            default: return 'bg-zinc-200 text-black';
        }
    };

    return (
        <Wrapper
            identity={{
                displayName: "ATOM: METADATA",
                filePath: "zap/sections/molecules/email/atoms/EmailAtoms.tsx",
                type: "Atom/Data-Display",
                architecture: "LEVEL 1 // GENESIS"
            }}
        >
            <div className={`flex flex-wrap gap-2 ${className}`}>
                {tags.map((tag, idx) => (
                    <span
                        key={idx}
                        className={`text-[10px] font-black px-3 py-1 border-2 border-black shadow-[2px_2px_0px_0px_#000] uppercase ${getTagStyles(tag.type)}`}
                    >
                        {tag.label}
                    </span>
                ))}
            </div>
        </Wrapper>
    );
};
